/**
 * Unit tests for Plan 34 Phase 4b — applyBundle (consumer-side).
 *
 * Round-trips a real bundle (CA + node cert via openssl, real GCM
 * encryption) through applyBundle and asserts the on-disk artefacts:
 * TLS files at the expected paths/modes, override-config.yml carries the
 * cluster wiring with the correct mTLS pointers.
 */

const assert = require('node:assert/strict');
const fs = require('node:fs');
const path = require('node:path');
const os = require('node:os');
const { execFileSync } = require('node:child_process');
const yaml = require('js-yaml');

const ClusterCA = require('../../src/bootstrap/ClusterCA');
const Bundle = require('../../src/bootstrap/Bundle');
const BundleEncryption = require('../../src/bootstrap/BundleEncryption');
const applyBundleMod = require('../../src/bootstrap/applyBundle');

const PASSPHRASE = 'test-pass-1234';

/** Build a real, signed bundle in `caDir` so the test exercises the genuine
 *  encryption + validation path. */
function makeArmoredBundle (caDir, overrides = {}) {
  const ca = new ClusterCA({ dir: caDir });
  ca.ensure();
  const { certPem, keyPem } = ca.issueNodeCert({
    coreId: 'core-b', ip: '203.0.113.7', hostname: 'core-b.mc.example.com'
  });
  const bundle = Bundle.assemble(Object.assign({
    cluster: {
      domain: 'mc.example.com',
      ackUrl: 'https://core-a.mc.example.com/system/admin/cores/ack',
      joinToken: '0123456789abcdef0123456789abcdef',
      caCertPem: ca.getCACertPem()
    },
    node: {
      id: 'core-b',
      ip: '203.0.113.7',
      hosting: 'us-east-1',
      url: 'https://core-b.mc.example.com',
      certPem,
      keyPem
    },
    platformSecrets: {
      auth: {
        adminAccessKey: 'admin-key-0123456789abcdef0123',
        filesReadTokenSecret: 'files-secret-0123456789abcdef0'
      }
    },
    rqlite: { raftPort: 4002, httpPort: 4001 }
  }, overrides));
  return BundleEncryption.encrypt(bundle, PASSPHRASE);
}

describe('[APPLYBUNDLE] applyBundle', function () {
  this.timeout(20_000);

  let tmp;

  before(function () {
    try { execFileSync('openssl', ['version'], { stdio: 'ignore' }); } catch {
      console.log('  skipping: openssl not available');
      this.skip();
    }
  });

  beforeEach(() => {
    tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'pryv-apply-'));
  });

  afterEach(() => {
    fs.rmSync(tmp, { recursive: true, force: true });
  });

  it('decrypts, validates, writes TLS files and override-config.yml', async () => {
    const armored = makeArmoredBundle(path.join(tmp, 'issuer-ca'));
    const configDir = path.join(tmp, 'config');
    const tlsDir = path.join(tmp, 'tls');

    const result = await applyBundleMod.applyBundle({
      armoredBundle: armored, passphrase: PASSPHRASE, configDir, tlsDir
    });

    assert.equal(result.coreId, 'core-b');
    assert.equal(result.ackUrl, 'https://core-a.mc.example.com/system/admin/cores/ack');
    assert.equal(result.joinToken, '0123456789abcdef0123456789abcdef');
    assert.match(result.tlsFingerprint, /^([0-9A-F]{2}:){31}[0-9A-F]{2}$/);

    // TLS files written, modes correct
    assert.equal(result.tlsPaths.caFile, path.join(tlsDir, 'ca.crt'));
    assert.equal(result.tlsPaths.certFile, path.join(tlsDir, 'node.crt'));
    assert.equal(result.tlsPaths.keyFile, path.join(tlsDir, 'node.key'));
    assert.ok(fs.readFileSync(result.tlsPaths.caFile, 'utf8').includes('BEGIN CERTIFICATE'));
    assert.ok(fs.readFileSync(result.tlsPaths.certFile, 'utf8').includes('BEGIN CERTIFICATE'));
    assert.ok(fs.readFileSync(result.tlsPaths.keyFile, 'utf8').includes('PRIVATE KEY'));
    assert.equal(fs.statSync(result.tlsPaths.keyFile).mode & 0o777, 0o600);
    assert.equal(fs.statSync(result.tlsPaths.caFile).mode & 0o777, 0o644);

    // override-config.yml written and parses to expected shape
    assert.equal(result.overridePath, path.join(configDir, 'override-config.yml'));
    const yamlSrc = fs.readFileSync(result.overridePath, 'utf8');
    assert.match(yamlSrc, /^# Generated by `bin\/master\.js --bootstrap`/);
    const parsed = yaml.load(yamlSrc);
    assert.equal(parsed.core.id, 'core-b');
    assert.equal(parsed.core.url, 'https://core-b.mc.example.com');
    assert.equal(parsed.core.ip, '203.0.113.7');
    assert.equal(parsed.dns.domain, 'mc.example.com');
    assert.equal(parsed.dnsLess.isActive, false);
    assert.equal(parsed.auth.adminAccessKey, 'admin-key-0123456789abcdef0123');
    assert.equal(parsed.auth.filesReadTokenSecret, 'files-secret-0123456789abcdef0');
    assert.equal(parsed.storages.engines.rqlite.raftPort, 4002);
    assert.equal(parsed.storages.engines.rqlite.url, 'http://localhost:4001');
    assert.deepEqual(parsed.storages.engines.rqlite.tls, {
      caFile: result.tlsPaths.caFile,
      certFile: result.tlsPaths.certFile,
      keyFile: result.tlsPaths.keyFile,
      verifyClient: true
    });
    // override file is 0600 (carries adminAccessKey)
    assert.equal(fs.statSync(result.overridePath).mode & 0o777, 0o600);
  });

  it('omits dnsLess override when bundle has no domain (DNSless multi-core)', async () => {
    const armored = makeArmoredBundle(path.join(tmp, 'ca'), {
      cluster: {
        domain: '',
        ackUrl: 'https://core-a.example.com/system/admin/cores/ack',
        joinToken: '0123456789abcdef0123456789abcdef',
        caCertPem: '__placeholder__'
      }
    });
    // The placeholder above won't pass Bundle.validate — fall back to a real CA.
    const ca = new ClusterCA({ dir: path.join(tmp, 'ca') });
    const realArmored = makeArmoredBundleWithDomain(ca, '');

    const result = await applyBundleMod.applyBundle({
      armoredBundle: realArmored,
      passphrase: PASSPHRASE,
      configDir: path.join(tmp, 'config'),
      tlsDir: path.join(tmp, 'tls')
    });
    const parsed = yaml.load(fs.readFileSync(result.overridePath, 'utf8'));
    assert.equal(parsed.dnsLess, undefined);
    assert.equal(parsed.dns, undefined);
    // armored unused — keep referenced so lint doesn't complain
    assert.ok(armored.length > 0);
  });

  it('throws on wrong passphrase (decryption fails)', async () => {
    const armored = makeArmoredBundle(path.join(tmp, 'ca'));
    await assert.rejects(
      applyBundleMod.applyBundle({
        armoredBundle: armored,
        passphrase: 'wrong',
        configDir: path.join(tmp, 'config'),
        tlsDir: path.join(tmp, 'tls')
      }),
      /authentication failed/
    );
    // Side-effect check: TLS dir not created on failure (we only create after decrypt)
    assert.equal(fs.existsSync(path.join(tmp, 'tls')), false);
  });

  it('throws on tampered ciphertext', async () => {
    const armored = makeArmoredBundle(path.join(tmp, 'ca'));
    // Flip a byte inside the b64 payload (between the armor markers) so
    // GCM auth fails. Replacing a single char inside the armor lines is
    // enough — base64 decoding still produces something that round-trips
    // to the wrong plaintext, then GCM rejects.
    const lines = armored.split('\n');
    // first content line is index 1 (0 is the BEGIN marker)
    lines[1] = lines[1].replace(/^./, c => c === 'A' ? 'B' : 'A');
    const tampered = lines.join('\n');
    await assert.rejects(
      applyBundleMod.applyBundle({
        armoredBundle: tampered,
        passphrase: PASSPHRASE,
        configDir: path.join(tmp, 'config'),
        tlsDir: path.join(tmp, 'tls')
      }),
      /authentication failed|tampered|envelope|invalid/
    );
  });

  it('rejects missing required arguments', async () => {
    await assert.rejects(applyBundleMod.applyBundle({}), /armoredBundle is required/);
    await assert.rejects(
      applyBundleMod.applyBundle({ armoredBundle: 'x' }),
      /passphrase is required/
    );
    await assert.rejects(
      applyBundleMod.applyBundle({ armoredBundle: 'x', passphrase: 'y' }),
      /configDir is required/
    );
  });

  describe('sha256Fingerprint()', () => {
    it('matches openssl x509 -fingerprint -sha256', () => {
      const ca = new ClusterCA({ dir: path.join(tmp, 'ca') });
      ca.ensure();
      const { certPem } = ca.issueNodeCert({ coreId: 'core-b', ip: '1.1.1.1' });
      const ours = applyBundleMod.sha256Fingerprint(certPem);

      const certPath = path.join(tmp, 'cert.pem');
      fs.writeFileSync(certPath, certPem);
      const opensslOut = execFileSync('openssl',
        ['x509', '-noout', '-fingerprint', '-sha256', '-in', certPath]).toString();
      const expected = opensslOut.split('=')[1].trim();
      assert.equal(ours, expected);
    });
  });
});

function makeArmoredBundleWithDomain (ca, domain) {
  ca.ensure();
  const { certPem, keyPem } = ca.issueNodeCert({ coreId: 'core-b', ip: '203.0.113.7' });
  const bundle = Bundle.assemble({
    cluster: {
      domain,
      ackUrl: 'https://core-a.example.com/system/admin/cores/ack',
      joinToken: '0123456789abcdef0123456789abcdef',
      caCertPem: ca.getCACertPem()
    },
    node: { id: 'core-b', ip: '203.0.113.7', certPem, keyPem },
    platformSecrets: {
      auth: {
        adminAccessKey: 'admin-key-0123456789abcdef0123',
        filesReadTokenSecret: 'files-secret-0123456789abcdef0'
      }
    },
    rqlite: { raftPort: 4002, httpPort: 4001 }
  });
  return BundleEncryption.encrypt(bundle, PASSPHRASE);
}
